//! DEBUG: dump the native LTX 3D-causal VAE decode on a fixed deterministic
//! latent for numeric cross-check against diffusers AutoencoderKLLTXVideo.decode.
//!
//! usage: ltx-vae-dump <knot> <out-prefix> [F] [H] [W]
//!
//! Pairs with ltx-knot-diffusers.py (Phase 3 VAE reference). Small F/H/W
//! (default 1x4x4 latent → 1x32x32 RGB after ×8 spatial) keep memory tiny.

use std::io::Write;

use distributed_inference::loader::KnotWeights;
use distributed_inference::model_ltx_vae::debug_decode_forward;

fn stats(v: &[f32]) -> (f32, f32, f32, f32) {
    let n = v.len() as f32;
    let mean = v.iter().sum::<f32>() / n;
    let var = v.iter().map(|x| (x - mean) * (x - mean)).sum::<f32>() / n;
    let mn = v.iter().cloned().fold(f32::INFINITY, f32::min);
    let mx = v.iter().cloned().fold(f32::NEG_INFINITY, f32::max);
    (mean, var.sqrt(), mn, mx)
}

fn main() {
    let args: Vec<String> = std::env::args().collect();
    if args.len() < 3 {
        eprintln!("usage: ltx-vae-dump <knot> <out-prefix> [F] [H] [W]");
        std::process::exit(2);
    }
    let knot_path = &args[1];
    let out_prefix = &args[2];
    let f: usize = args.get(3).and_then(|s| s.parse().ok()).unwrap_or(1);
    let h: usize = args.get(4).and_then(|s| s.parse().ok()).unwrap_or(4);
    let w: usize = args.get(5).and_then(|s| s.parse().ok()).unwrap_or(4);

    let knot = KnotWeights::load_metadata_only(knot_path).expect("load knot metadata");
    let out = debug_decode_forward(knot_path, &knot, f, h, w).expect("ltx vae decode");

    let bin_path = format!("{out_prefix}.bin");
    let json_path = format!("{out_prefix}.json");
    let mut file = std::fs::File::create(&bin_path).expect("create bin");
    for x in out.rgb.iter() {
        file.write_all(&x.to_le_bytes()).unwrap();
    }
    let (mean, std, mn, mx) = stats(&out.rgb);
    eprintln!(
        "rgb shape=({},{},{},{}) len={} mean={:+.5} std={:.5} min={:+.4} max={:+.4}",
        out.c,
        out.d,
        out.h,
        out.w,
        out.rgb.len(),
        mean,
        std,
        mn,
        mx
    );
    let manifest = format!(
        "{{\n  \"c\": {}, \"d\": {}, \"h\": {}, \"w\": {},\n  \"fields\": {{\n    \"rgb\": {{\"offset\": 0, \"len\": {}}}\n  }}\n}}\n",
        out.c,
        out.d,
        out.h,
        out.w,
        out.rgb.len()
    );
    std::fs::write(&json_path, manifest).expect("write json");
    eprintln!("wrote {bin_path} + {json_path}");
}
